        function gameLoop() {
            if (!gameRunning) return;

            // 清空画布
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // 更新
            updatePlayer();
            updatePlayerBullets();
            updateEnemies();
            updateExplosions();
            handleCollisions();

            // 绘制
            drawPlayer();
            drawPlayerBullets();
            drawEnemies();
            drawExplosions();

            // 更新UI
            document.getElementById('score').textContent = score;
            document.getElementById('health').textContent = playerHealth;

            requestAnimationFrame(gameLoop);
        }

        // 游戏结束
