            player.bullets.forEach((pBullet, pBulletIndex) => {
                enemies.forEach((enemy, enemyIndex) => {
                    if (checkCollision(pBullet, enemy)) {
                        // 敌人被击中，爆炸
                        explosions.push({ x: enemy.x + enemy.width / 2, y: enemy.y + enemy.height / 2, radius: 5, alpha: 1 });
                        enemies.splice(enemyIndex, 1);
                        player.bullets.splice(pBulletIndex, 1);
                        score += (pBullet.type === BULLET_TYPE.SPECIAL ? 20 : 10); // 特殊子弹得分更高

                        // 击毙敌人有概率获得特殊子弹
                        if (Math.random() < 0.15) { // 15% 概率
                            player.specialBulletCount++;
                        }
                        return;
                    }
                });
            });

            // 敌人子弹与玩家
            enemies.forEach(enemy => {
                enemy.bullets.forEach((eBullet, eBulletIndex) => {
                    if (checkCollision(eBullet, player)) {
                        playerHealth -= 10;
                        enemy.bullets.splice(eBulletIndex, 1);
                        if (playerHealth <= 0) {
                            gameOver();
                        }
                    }
                });
            });

            // 敌人与玩家
            enemies.forEach((enemy, enemyIndex) => {
                if (checkCollision(enemy, player)) {
                    playerHealth -= 20;
                    explosions.push({ x: enemy.x + enemy.width / 2, y: enemy.y + enemy.height / 2, radius: 5, alpha: 1 });
                    enemies.splice(enemyIndex, 1);
                    if (playerHealth <= 0) {
                        gameOver();
                    }
                }
            });
        }

        // 游戏循环
        function gameLoop() {
            if (!gameRunning) return;

            // 清空画布
            ctx.clearRect(0, 0, canvas.width, canvas.height);

            // 更新
            updatePlayer();
            updatePlayerBullets();
            updateEnemies();
            updateExplosions();
            handleCollisions();

            // 绘制
            drawPlayer();
            drawPlayerBullets();
            drawEnemies();
            drawExplosions();

            // 更新UI
            document.getElementById('score').textContent = score;
            document.getElementById('health').textContent = playerHealth;

            requestAnimationFrame(gameLoop);
        }

        // 游戏结束
        function gameOver() {
            gameRunning = false;
            document.getElementById('final-score').textContent = score;
            document.getElementById('game-over').style.display = 'block';
        }

        // 重新开始游戏
        function startGame() {
            document.getElementById('game-over').style.display = 'none';

            // 重置游戏状态
            score = 0;
            playerHealth = 100;
            player.x = canvas.width / 2 - 20;
            player.y = canvas.height - 80;
            player.bullets = [];
            player.lastShot = 0;
            player.specialBulletCount = 0;
            player.specialBulletActive = false;
            player.specialBulletTimer = 0;
            enemies.length = 0;
            explosions.length = 0;

            document.getElementById('score').textContent = score;
            document.getElementById('health').textContent = playerHealth;

            gameRunning = true;
            gameLoop();
        }

        // 初始启动游戏
        startGame();

    </script>
